import {
  type KeyboardEvent,
  useCallback,
  useEffect,
  useId,
  useMemo,
  useRef,
  useState,
} from "react";
import { Command as CommandPrimitive } from "cmdk";
import { cn } from "../../lib/utils";
import {
  CommandGroup,
  CommandInput,
  CommandItem,
  CommandList,
} from "../ui/command";
import { Label } from "../ui/label";
import { Skeleton } from "../ui/skeleton";

export type Option = Record<"value" | "label", string> & Record<string, string>;

type AutoCompleteProps = {
  id?: string;
  label: string;
  options: Option[];
  emptyMessage: string;
  value?: string;
  onValueChange?: (value: Option) => void;
  onInputChange?: (value: string) => void;
  isLoading?: boolean;
  disabled?: boolean;
  placeholder?: string;
  showRequired?: boolean;
  required?: boolean;
  name?: string;
};

export const AutoComplete = ({
  id,
  label,
  options,
  name,
  placeholder,
  emptyMessage,
  value,
  onValueChange,
  onInputChange,
  disabled,
  isLoading = false,
  showRequired = true,
  required = true,
}: AutoCompleteProps) => {
  const inputRef = useRef<HTMLInputElement>(null);
  const [isOpen, setOpen] = useState(false);
  const [inputValue, setInputValue] = useState<string>(value || "");
  const fallbackId = useId();
  const inputId = id ?? name ?? fallbackId;

  // Update inputValue when value prop changes
  useEffect(() => {
    setInputValue(value || "");
  }, [value]);

  const labelContent = useMemo(() => {
    return (
      <>
        {label}
        {showRequired ? (
          required ? (
            <span className="text-xs text-neutral-500">required</span>
          ) : (
            <span className="text-xs font-normal text-neutral-500">
              optional
            </span>
          )
        ) : null}
      </>
    );
  }, [label, required, showRequired]);

  const handleInputChange = useCallback(
    (value: string) => {
      setInputValue(value);
      onInputChange?.(value);
    },
    [onInputChange],
  );

  const handleKeyDown = useCallback(
    (event: KeyboardEvent<HTMLDivElement>) => {
      const input = inputRef.current;
      if (!input) {
        return;
      }

      // Keep the options displayed when the user is typing
      if (!isOpen) {
        setOpen(true);
      }

      if (event.key === "Enter" && input.value !== "") {
        const optionToSelect = options.find(
          (option) => option.label === input.value,
        );
        if (optionToSelect) {
          onValueChange?.(optionToSelect);
        }
      }

      if (event.key === "Escape") {
        input.blur();
      }
    },
    [isOpen, options, onValueChange],
  );

  const handleBlur = useCallback(() => {
    setOpen(false);
  }, []);

  const handleSelectOption = useCallback(
    (selectedOption: Option) => {
      onValueChange?.(selectedOption);

      // This is a hack to prevent the input from being focused after the user selects an option
      setTimeout(() => {
        inputRef?.current?.blur();
      }, 0);
    },
    [onValueChange],
  );

  return (
    <CommandPrimitive label={label} onKeyDown={handleKeyDown}>
      <div className="flex flex-1 flex-col gap-2">
        <Label className={cn(required ? "gap-1" : "")} htmlFor={inputId}>
          {labelContent}
        </Label>
        <CommandInput
          id={inputId}
          name={name}
          disabled={disabled}
          onBlur={handleBlur}
          onFocus={() => setOpen(true)}
          onValueChange={isLoading ? undefined : handleInputChange}
          placeholder={placeholder}
          ref={inputRef}
          value={inputValue}
        />
      </div>
      <div className="relative">
        <div
          className={cn(
            "absolute top-0 z-10 mt-2 w-full bg-white rounded-xl outline-none animate-in fade-in-0 zoom-in-95",
            isOpen ? "block" : "hidden",
          )}
        >
          <CommandList className="bg-white rounded-lg ring-1 shadow-lg ring-slate-200">
            {isLoading ? (
              <CommandPrimitive.Loading>
                <div className="p-1">
                  <Skeleton className="w-full h-8" />
                </div>
              </CommandPrimitive.Loading>
            ) : null}
            {options.length > 0 && !isLoading ? (
              <CommandGroup>
                {options.map((option) => {
                  return (
                    <CommandItem
                      className={cn("flex gap-2 items-center w-full")}
                      key={option.value}
                      onMouseDown={(event) => {
                        event.preventDefault();
                        event.stopPropagation();
                      }}
                      onSelect={() => handleSelectOption(option)}
                      value={option.label}
                    >
                      {option.label}
                    </CommandItem>
                  );
                })}
              </CommandGroup>
            ) : null}
            {!isLoading ? (
              <CommandPrimitive.Empty className="px-2 py-3 text-sm text-center rounded-sm select-none">
                {emptyMessage}
              </CommandPrimitive.Empty>
            ) : null}
          </CommandList>
        </div>
      </div>
    </CommandPrimitive>
  );
};

